package main

import (
	"io"
	"log"
	"net/http"
)

func proxyHandler(w http.ResponseWriter, r *http.Request) {
	targetURL := r.URL.Query().Get("url")
	if targetURL == "" {
		http.Error(w, "URL parameter is missing", http.StatusBadRequest)
		return
	}

	resp, err := http.Get(targetURL)
	if err != nil {
		log.Printf("Error fetching URL %s: %v", targetURL, err)
		http.Error(w, "Failed to fetch content from target URL", http.StatusInternalServerError)
		return
	}
	defer resp.Body.Close()

	for key, values := range resp.Header {
		for _, value := range values {
			w.Header().Add(key, value)
		}
	}

	w.WriteHeader(resp.StatusCode)

	if _, err := io.Copy(w, resp.Body); err != nil {
		log.Printf("Error copying response body for URL %s: %v", targetURL, err)
	}
}

func main() {
	http.HandleFunc("/proxy", proxyHandler)
	log.Println("Starting webhook proxy server on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}